return ['x-generator'=>'GlotPress/4.0.0-rc.1','translation-revision-date'=>'2025-10-16 21:41:48+0000','plural-forms'=>'nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2);','project-id-version'=>'RocketGenius - Gravity Forms','language'=>'uk_UA','messages'=>['Payment Failed'=>'Платіж не пройшов','Payment Completed'=>'Оплату здійснено','Payment Authorized'=>'Платіж авторизовано','Logged In User'=>'Поточний користувач','Every Minute'=>'Щохвилини','License details are not available at this time.'=>'Деталі ліцензії наразі недоступні.','There was an error while validating your license key; please try again later. If the problem persists, please %1$scontact support%2$s.'=>'Під час перевірки ліцензійного ключа сталася помилка; спробуйте пізніше. Якщо проблема не зникає, %1$sзв’яжіться зі службою підтримки%2$s.',', Row {0}'=>', Рядок {0}','Theme Colors'=>'Кольори теми','Default Colors'=>'Кольори за замовчуванням','Custom Colors'=>'Власні кольори','Descending'=>'Спадання','Ascending'=>'Зростання','Default Sort Order'=>'Порядок сортування за замовчуванням','Default Sort Column'=>'Колонка сортування за замовчуванням','Sorting Options'=>'Параметри сортування','field added to form'=>'поле додано у форму','Square'=>'Квадрат','Circle'=>'Коло','Style'=>'Стиль','No Card'=>'Немає картки','Card'=>'Картка','Image Choice Styles'=>'Стилі вибору зображення','Show Form Description'=>'Показати опис форми','Show Form Title'=>'Показати заголовок форми','If a form uses the Image Choice field, or has Conversational Mode enabled, the importer will import the images and save them in your media library.'=>'Якщо у формі використовується поле «Вибір зображення» або увімкнено режим розмови, імпортер імпортує зображення і зберігає їх у вашій медіатеці.','Enable this option to allow the user to select multiple choices. Disabling this option after entries with multiple choices have been submitted will hide the values for those entries.'=>'Увімкніть цю оп